class Solution(object):
    def cherryPickup(self, grid):
        m, n = len(grid), len(grid[0])
        memo = {}

        def dp(r, c1, c2):
            if r == m or c1 < 0 or c1 >= n or c2 < 0 or c2 >= n:
                return 0
            if (r, c1, c2) in memo:
                return memo[(r, c1, c2)]

            result = 0
            for dc1 in [-1, 0, 1]:
                for dc2 in [-1, 0, 1]:
                    result = max(result, dp(r+1, c1+dc1, c2+dc2))

            cherries = grid[r][c1]
            if c1 != c2:
                cherries += grid[r][c2]

            result += cherries
            memo[(r, c1, c2)] = result
            return result

        return dp(0, 0, n-1)
